import { NextResponse } from "next/server";
import nodemailer from "nodemailer";

export const runtime = "nodejs";

type ContactPayload = {
  name: string;
  company: string;
  email: string;
  inquiryType?: string;
  message: string;
};

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function validatePayload(payload: Partial<ContactPayload>) {
  const name = payload.name?.trim() ?? "";
  const company = payload.company?.trim() ?? "";
  const email = payload.email?.trim() ?? "";
  const inquiryType = payload.inquiryType?.trim() ?? "";
  const message = payload.message?.trim() ?? "";

  if (!name || !company || !email || !message) {
    return { valid: false, error: "All fields are required." };
  }

  if (!EMAIL_REGEX.test(email)) {
    return { valid: false, error: "Please provide a valid email address." };
  }

  if (message.length < 20) {
    return {
      valid: false,
      error: "Please include more detail in your message.",
    };
  }

  return { valid: true, data: { name, company, email, inquiryType, message } };
}

function getMissingEnvVar() {
  const required = [
    "SMTP_HOST",
    "SMTP_PORT",
    "SMTP_USER",
    "SMTP_PASS",
  ] as const;

  return required.find((key) => !process.env[key]);
}

export async function POST(request: Request) {
  try {
    const body = (await request.json()) as Partial<ContactPayload>;
    const validation = validatePayload(body);

    if (!validation.valid) {
      return NextResponse.json(
        { success: false, error: validation.error },
        { status: 400 },
      );
    }

    const missingVar = getMissingEnvVar();
    if (missingVar) {
      return NextResponse.json(
        {
          success: false,
          error: `Server email is not configured (${missingVar}).`,
        },
        { status: 500 },
      );
    }

    const transporter = nodemailer.createTransport({
      host: process.env.SMTP_HOST,
      port: Number(process.env.SMTP_PORT),
      secure: Number(process.env.SMTP_PORT) === 465,
      auth: {
        user: process.env.SMTP_USER,
        pass: process.env.SMTP_PASS,
      },
    });

    const { name, company, email, inquiryType, message } = validation.data;

    const contactToEmail = process.env.CONTACT_TO_EMAIL ?? "info@purfavor.com";

    await transporter.sendMail({
      from: `"Purfavor Contact Form" <${process.env.SMTP_USER}>`,
      to: contactToEmail,
      replyTo: email,
      subject: `New partnership inquiry from ${name} (${company})`,
      text: [
        "New contact form submission",
        "",
        `Name: ${name}`,
        `Company: ${company}`,
        `Email: ${email}`,
        `I am a: ${inquiryType || "Not specified"}`,
        "",
        "Message:",
        message,
      ].join("\n"),
    });

    return NextResponse.json({ success: true });
  } catch {
    return NextResponse.json(
      {
        success: false,
        error: "We could not send your inquiry. Please try again.",
      },
      { status: 500 },
    );
  }
}
